{"content":"#!/usr/bin/env python3
"""Merge user data from three sources with conflict resolution."""

import json
import pandas as pd
from datetime import datetime

# Read source A (JSON) - highest priority
with open('/data/source_a/users.json', 'r') as f:
    source_a_data = json.load(f)

source_a = []
for user in source_a_data:
    source_a.append({
        'user_id': int(user['id']),
        'name': user['full_name'],
        'email': user['email'],
        'created_date': user['registration_date'],
        'status': user.get('status', None),
        '_source': 'source_a'
    })

# Read source B (CSV) - secondary priority
source_b_df = pd.read_csv('/data/source_b/users.csv')
source_b = []
for _, row in source_b_df.iterrows():
    source_b.append({
        'user_id': int(row['user_id']),
        'name': row['name'],
        'email': row['email_address'],
        'created_date': row['created_at'],
        'status': str(row['is_active']).lower() if pd.notna(row['is_active']) else None,
        '_source': 'source_b'
    })

# Read source C (Parquet) - tertiary priority
source_c_df = pd.read_parquet('/data/source_c/users.parquet')
source_c = []
for _, row in source_c_df.iterrows():
    source_c.append({
        'user_id': int(row['userId']),
        'name': row['userName'],
        'email': row['email'],
        'created_date': row['joined'],
        'status': str(row['active']).lower() if pd.notna(row['active']) else None,
        '_source': 'source_c'
    })

# Combine all sources
all_sources = {
    'source_a': source_a,
    'source_b': source_b,
    'source_c': source_c
}

# Collect all unique user_ids
all_user_ids = set()
for source in [source_a, source_b, source_c]:
    for user in source:
        all_user_ids.add(user['user_id'])

# Build conflict report and merged data
conflicts = []
merged_users = {}

for uid in sorted(all_user_ids):
    # Get users from each source
    users_by_source = {}
    for src_name, users in all_sources.items():
        for user in users:
            if user['user_id'] == uid:
                users_by_source[src_name] = user
                break

    # Check for conflicts on each field
    fields_to_check = ['name', 'email', 'created_date', 'status']

    for field in fields_to_check:
        values = {}
        for src_name in ['source_a', 'source_b', 'source_c']:
            if src_name in users_by_source:
                val = users_by_source[src_name].get(field, None)
                if val is not None:
                    values[src_name] = val

        # Check if there are different values for the same field
        unique_values = set(str(v) for v in values.values())
        if len(unique_values) > 1:
            # There's a conflict
            conflict_entry = {
                'user_id': uid,
                'field': field,
                'values': {},
                'selected': None
            }
            for src_name in ['source_a', 'source_b', 'source_c']:
                if src_name in users_by_source:
                    val = users_by_source[src_name].get(field, None)
                    if val is not None:
                        conflict_entry['values'][src_name] = val

            # Select based on priority
            for src_name in ['source_a', 'source_b', 'source_c']:
                if src_name in users_by_source:
                    conflict_entry['selected'] = users_by_source[src_name][field]
                    break

            conflicts.append(conflict_entry)

    # Build merged user record using priority
    merged_user = {
        'user_id': uid,
        'name': None,
        'email': None,
        'created_date': None,
        'status': None
    }

    for field in ['name', 'email', 'created_date', 'status']:
        # Use priority order
        for src_name in ['source_a', 'source_b', 'source_c']:
            if src_name in users_by_source:
                val = users_by_source[src_name].get(field, None)
                if val is not None:
                    merged_user[field] = val
                    break

    # Format date to YYYY-MM-DD
    if merged_user['created_date']:
        try:
            dt = datetime.strptime(merged_user['created_date'], '%Y-%m-%d')
            merged_user['created_date'] = dt.strftime('%Y-%m-%d')
        except ValueError:
            pass

    merged_users[uid] = merged_user

# Create DataFrame and save as parquet
merged_df = pd.DataFrame(list(merged_users.values()))
merged_df.to_parquet('/app/merged_users.parquet', index=False)

# Save conflict report
report = {
    'total_conflicts': len(conflicts),
    'conflicts': conflicts
}

with open('/app/conflicts.json', 'w') as f:
    json.dump(report, f, indent=2)

print(f"Total unique users: {len(all_user_ids)}")
print(f"Total conflicts: {len(conflicts)}")
print("Merged users saved to /app/merged_users.parquet")
print("Conflict report saved to /app/conflicts.json")
","path":"/app/merge_users.py"}

